@spsbbi.proof
def prove_spsbbi(proof: TheoryProofAuthor) -> CompleteProof:
    from metamath_setmm_provider.shards.s000 import syl
    from metamath_setmm_provider.shards.s001 import biimp, biimpr, impbid
    from metamath_setmm_provider.shards.s009 import alimi


    _step_1 = proof.use(biimp, subst={"ph": "ph", "ps": "ps"})  # ⊢ wi(wb(ph, ps), wi(ph, ps))
    _step_2 = proof.use(
        alimi,
        _step_1,
        subst={
            "x": "x",
        },
    )  # ⊢ wi(wal(wb(ph, ps), x), wal(wi(ph, ps), x))
    _step_3 = proof.use(
        spsbim,
        subst={
            "ph": "ph",
            "ps": "ps",
            "x": "x",
            "t": "t",
        },
    )  # ⊢ wi(wal(wi(ph, ps), x), wi(wsb(ph, x, t), wsb(ps, x, t)))
    _step_4 = proof.use(
        syl,
        _step_2,
        _step_3,
    )  # ⊢ wi(wal(wb(ph, ps), x), wi(wsb(ph, x, t), wsb(ps, x, t)))
    _step_5 = proof.use(biimpr, subst={"ph": "ph", "ps": "ps"})  # ⊢ wi(wb(ph, ps), wi(ps, ph))
    _step_6 = proof.use(
        alimi,
        _step_5,
        subst={
            "x": "x",
        },
    )  # ⊢ wi(wal(wb(ph, ps), x), wal(wi(ps, ph), x))
    _step_7 = proof.use(
        spsbim,
        subst={
            "ph": "ps",
            "ps": "ph",
            "x": "x",
            "t": "t",
        },
    )  # ⊢ wi(wal(wi(ps, ph), x), wi(wsb(ps, x, t), wsb(ph, x, t)))
    _step_8 = proof.use(
        syl,
        _step_6,
        _step_7,
    )  # ⊢ wi(wal(wb(ph, ps), x), wi(wsb(ps, x, t), wsb(ph, x, t)))
    _step_9 = proof.use(
        impbid,
        _step_4,
        _step_8,
    )  # ⊢ wi(wal(wb(ph, ps), x), wb(wsb(ph, x, t), wsb(ps, x, t)))
    return proof.qed(_step_9)


