@sban.proof
def prove_sban(proof: TheoryProofAuthor) -> CompleteProof:
    from metamath_setmm_provider.shards.s001 import impbii
    from metamath_setmm_provider.shards.s002 import imp, jca, pm3_2, simpl, simpr


    _step_1 = proof.use(simpl, subst={"ph": "ph", "ps": "ps"})  # ⊢ wi(wa(ph, ps), ph)
    _step_2 = proof.use(
        sbimi,
        _step_1,
        subst={
            "x": "x",
            "t": "y",
        },
    )  # ⊢ wi(wsb(wa(ph, ps), x, y), wsb(ph, x, y))
    _step_3 = proof.use(simpr, subst={"ph": "ph", "ps": "ps"})  # ⊢ wi(wa(ph, ps), ps)
    _step_4 = proof.use(
        sbimi,
        _step_3,
        subst={
            "x": "x",
            "t": "y",
        },
    )  # ⊢ wi(wsb(wa(ph, ps), x, y), wsb(ps, x, y))
    _step_5 = proof.use(
        jca,
        _step_2,
        _step_4,
    )  # ⊢ wi(wsb(wa(ph, ps), x, y), wa(wsb(ph, x, y), wsb(ps, x, y)))
    _step_6 = proof.use(pm3_2, subst={"ph": "ph", "ps": "ps"})  # ⊢ wi(ph, wi(ps, wa(ph, ps)))
    _step_7 = proof.use(
        sb2imi,
        _step_6,
        subst={
            "x": "x",
            "t": "y",
        },
    )  # ⊢ wi(wsb(ph, x, y), wi(wsb(ps, x, y), wsb(wa(ph, ps), x, y)))
    _step_8 = proof.use(
        imp,
        _step_7,
    )  # ⊢ wi(wa(wsb(ph, x, y), wsb(ps, x, y)), wsb(wa(ph, ps), x, y))
    _step_9 = proof.use(
        impbii,
        _step_5,
        _step_8,
    )  # ⊢ wb(wsb(wa(ph, ps), x, y), wa(wsb(ph, x, y), wsb(ps, x, y)))
    return proof.qed(_step_9)


