    _step_7 = proof.use(nfsb, _step_6, subst={"x": "y", "y": "w"})  # ⊢ wnf(wsb(ph, y, w), z)
    _step_8 = proof.use(
        sb8e,
        _step_7,
        subst={
            "x": "x",
        },
    )  # ⊢ wb(wex(wsb(ph, y, w), x), wex(wsb(wsb(ph, y, w), x, z), z))
    _step_9 = proof.use(
        exbii,
        _step_8,
        subst={
            "x": "w",
        },
    )  # ⊢ wb(wex(wex(wsb(ph, y, w), x), w), wex(wex(wsb(wsb(ph, y, w), x, z), z), w))
    _step_10 = proof.use(
        excom,
        subst={
            "ph": "wsb(wsb(ph, y, w), x, z)",
            "x": "w",
            "y": "z",
        },
    )  # ⊢ wb(wex(wex(wsb(wsb(ph, y, w), x, z), z), w), wex(wex(wsb(wsb(ph, y, w), x, z), w), z))
    _step_11 = proof.use(
        mm_3bitri,
        _step_5,
        _step_9,
        _step_10,
    )  # ⊢ wb(wex(wex(ph, y), x), wex(wex(wsb(wsb(ph, y, w), x, z), w), z))
    return proof.qed(_step_11)

